1	import { useState, useEffect } from "react";
2	import {
3	  snapshotsApi,
4	  type RestorePreview,
5	  type RestorePreviewRow,
6	  type RestoreRequest,
7	} from "../../api/bulkUpdate";
8	import { showToast } from "../../shared/components/Toast";
9	
10	// ---------------------------------------------------------------------------
11	// Shared styles (local copies — only what this modal needs)
12	// ---------------------------------------------------------------------------
13	
14	const BTN_PRIMARY: React.CSSProperties = {
15	  padding: "6px 16px",
16	  borderRadius: "6px",
17	  border: "none",
18	  background: "var(--io-accent)",
19	  color: "var(--io-text-on-accent)",
20	  fontWeight: 600,
21	  fontSize: "13px",
22	  cursor: "pointer",
23	};
24	
25	const BTN_SECONDARY: React.CSSProperties = {
26	  padding: "6px 16px",
27	  borderRadius: "6px",
28	  border: "1px solid var(--io-border)",
29	  background: "var(--io-surface-sunken)",
30	  color: "var(--io-text-primary)",
31	  fontWeight: 500,
32	  fontSize: "13px",
33	  cursor: "pointer",
34	};
35	
36	const TABLE: React.CSSProperties = {
37	  width: "100%",
38	  borderCollapse: "collapse" as const,
39	  fontSize: "12px",
40	};
41	
42	const TH: React.CSSProperties = {
43	  textAlign: "left" as const,
44	  padding: "6px 10px",
45	  borderBottom: "1px solid var(--io-border)",
46	  color: "var(--io-text-muted)",
47	  fontWeight: 600,
48	  background: "var(--io-surface-sunken)",
49	};
50	
51	const TD: React.CSSProperties = {
52	  padding: "6px 10px",
53	  borderBottom: "1px solid var(--io-border)",
54	  color: "var(--io-text-primary)",
55	  verticalAlign: "top" as const,
56	};
57	
58	// ---------------------------------------------------------------------------
59	// Badge — inline status pill
60	// ---------------------------------------------------------------------------
61	
62	function Badge({
63	  children,
64	  color,
65	}: {
66	  children: React.ReactNode;
67	  color: "success" | "warning" | "danger" | "accent" | "muted";
68	}) {
69	  const colors = {
70	    success: { bg: "var(--io-success-subtle)", fg: "var(--io-success)" },
71	    warning: { bg: "var(--io-warning-subtle)", fg: "var(--io-warning)" },
72	    danger: { bg: "var(--io-danger-subtle)", fg: "var(--io-danger)" },
73	    accent: { bg: "var(--io-accent-subtle)", fg: "var(--io-accent)" },
74	    muted: { bg: "var(--io-surface-sunken)", fg: "var(--io-text-muted)" },
75	  };
76	  const c = colors[color];
77	  return (
78	    <span
79	      style={{
80	        display: "inline-block",
81	        padding: "2px 8px",
82	        borderRadius: "999px",
83	        fontSize: "11px",
84	        fontWeight: 600,
85	        background: c.bg,
86	        color: c.fg,
87	      }}
88	    >
89	      {children}
90	    </span>
91	  );
92	}
93	
94	// ---------------------------------------------------------------------------
95	// RestorePreviewDiffTable — renders field-level diff rows
96	// ---------------------------------------------------------------------------
97	
98	function RestorePreviewDiffTable({
99	  rows,
100	  mode,
101	  selectedIds,
102	  onToggle,
103	}: {
104	  rows: RestorePreviewRow[];
105	  mode: "all" | "selective";
106	  selectedIds: Set<string>;
107	  onToggle: (id: string) => void;
108	}) {
109	  if (rows.length === 0) {
110	    return (
111	      <p
112	        style={{
113	          padding: "var(--io-space-4)",
114	          color: "var(--io-text-muted)",
115	          fontSize: "12px",
116	        }}
117	      >
118	        No rows in this snapshot.
119	      </p>
120	    );
121	  }
122	
123	  // Collect all unique fields across all rows for table columns
124	  const allFields = Array.from(
125	    new Set(
126	      rows.flatMap((r) =>
127	        Object.keys(r.snapshot_values).filter((k) => k !== "id"),
128	      ),
129	    ),
130	  ).slice(0, 8); // limit columns for readability
131	
132	  return (
133	    <table style={{ ...TABLE, fontSize: "11px" }}>
134	      <thead>
135	        <tr>
136	          {mode === "selective" && <th style={{ ...TH, width: 32 }}></th>}
137	          <th style={TH}>ID</th>
138	          <th style={{ ...TH, width: 80 }}>Status</th>
139	          {allFields.map((f) => (
140	            <th key={f} style={TH}>
141	              {f}
142	            </th>
143	          ))}
144	        </tr>
145	      </thead>
146	      <tbody>
147	        {rows.map((row) => {
148	          const isSelected = selectedIds.has(row.id);
149	          const hasChanges = row.changed_fields.length > 0;
150	          return (
151	            <tr
152	              key={row.id}
153	              style={{
154	                background: row.conflicted
155	                  ? "var(--io-warning-subtle)"
156	                  : isSelected && mode === "selective"
157	                    ? "var(--io-accent-subtle)"
158	                    : undefined,
159	                cursor: mode === "selective" ? "pointer" : undefined,
160	              }}
161	              onClick={() => mode === "selective" && onToggle(row.id)}
162	            >
163	              {mode === "selective" && (
164	                <td style={{ ...TD, textAlign: "center" as const }}>
165	                  <input
166	                    type="checkbox"
167	                    checked={isSelected}
168	                    onChange={() => onToggle(row.id)}
169	                    onClick={(e) => e.stopPropagation()}
170	                  />
171	                </td>
172	              )}
173	              <td
174	                style={{
175	                  ...TD,
176	                  fontFamily: "monospace",
177	                  fontSize: "10px",
178	                  color: "var(--io-text-muted)",
179	                }}
180	              >
181	                {row.id.slice(0, 8)}…
182	              </td>
183	              <td style={TD}>
184	                {row.conflicted ? (
185	                  <span
186	                    style={{
187	                      color: "var(--io-warning)",
188	                      fontWeight: 600,
189	                      fontSize: "11px",
190	                    }}
191	                  >
192	                    &#9888; Conflict
193	                  </span>
194	                ) : hasChanges ? (
195	                  <Badge color="accent">Changed</Badge>
196	                ) : (
197	                  <Badge color="muted">Same</Badge>
198	                )}
199	              </td>
200	              {allFields.map((field) => {
201	                const snapVal = row.snapshot_values[field];
202	                const currVal = row.current_values[field];
203	                const isChanged = row.changed_fields.includes(field);
204	                const snapStr =
205	                  snapVal === null || snapVal === undefined
206	                    ? "—"
207	                    : String(snapVal).replace(/^"|"$/g, "");
208	                const currStr =
209	                  currVal === null || currVal === undefined
210	                    ? "—"
211	                    : String(currVal).replace(/^"|"$/g, "");
212	                return (
213	                  <td
214	                    key={field}
215	                    style={{
216	                      ...TD,
217	                      background: isChanged
218	                        ? "var(--io-danger-subtle)"
219	                        : undefined,
220	                    }}
221	                  >
222	                    {isChanged ? (
223	                      <div
224	                        style={{
225	                          display: "flex",
226	                          flexDirection: "column",
227	                          gap: 2,
228	                        }}
229	                      >
230	                        <span
231	                          style={{
232	                            color: "var(--io-danger)",
233	                            textDecoration: "line-through",
234	                            fontSize: "10px",
235	                          }}
236	                        >
237	                          {currStr}
238	                        </span>
239	                        <span
240	                          style={{
241	                            color: "var(--io-success)",
242	                            fontSize: "10px",
243	                          }}
244	                        >
245	                          {snapStr}
246	                        </span>
247	                      </div>
248	                    ) : (
249	                      <span
250	                        style={{
251	                          color: "var(--io-text-muted)",
252	                          fontSize: "10px",
253	                        }}
254	                      >
255	                        {snapStr}
256	                      </span>
257	                    )}
258	                  </td>
259	                );
260	              })}
261	            </tr>
262	          );
263	        })}
264	      </tbody>
265	    </table>
266	  );
267	}
268	
269	// ---------------------------------------------------------------------------
270	// RestorePreviewModal — multi-step restore preview with field-level diff
271	// ---------------------------------------------------------------------------
272	
273	export function RestorePreviewModal({
274	  snapshotId,
275	  snapshotLabel,
276	  onClose,
277	  onRestored,
278	}: {
279	  snapshotId: string;
280	  snapshotLabel?: string | null;
281	  onClose: () => void;
282	  onRestored: (result: {
283	    rows_restored: number;
284	    safety_snapshot_id: string | null;
285	  }) => void;
286	}) {
287	  const [step, setStep] = useState<1 | 2 | 3>(1);
288	  const [preview, setPreview] = useState<RestorePreview | null>(null);
289	  const [loadError, setLoadError] = useState<string | null>(null);
290	  const [mode, setMode] = useState<"all" | "selective">("all");
291	  const [selectedRowIds, setSelectedRowIds] = useState<Set<string>>(new Set());
292	  const [createSafetySnapshot, setCreateSafetySnapshot] = useState(true);
293	  const [isRestoring, setIsRestoring] = useState(false);
294	
295	  // Load preview on mount
296	  useEffect(() => {
297	    snapshotsApi
298	      .restorePreview(snapshotId)
299	      .then((res) => {
300	        if (res.success) {
301	          setPreview(res.data);
302	          setStep(2);
303	        } else {
304	          setLoadError(res.error.message);
305	        }
306	      })
307	      .catch(() => {
308	        setLoadError("Network error loading restore preview");
309	      });
310	  }, [snapshotId]);
311	
312	  const toggleRow = (id: string) => {
313	    setSelectedRowIds((prev) => {
314	      const next = new Set(prev);
315	      if (next.has(id)) next.delete(id);
316	      else next.add(id);
317	      return next;
318	    });
319	  };
320	
321	  const selectAll = () => {
322	    if (preview) setSelectedRowIds(new Set(preview.rows.map((r) => r.id)));
323	  };
324	
325	  const clearAll = () => setSelectedRowIds(new Set());
326	
327	  const rowCount =
328	    mode === "all" ? (preview?.total_rows ?? 0) : selectedRowIds.size;
329	
330	  const handleRestore = async () => {
331	    setIsRestoring(true);
332	    const req: RestoreRequest = {
333	      mode,
334	      create_safety_snapshot: createSafetySnapshot,
335	      row_ids: mode === "selective" ? Array.from(selectedRowIds) : undefined,
336	    };
337	    try {
338	      const res = await snapshotsApi.restore(snapshotId, req);
339	      if (res.success) {
340	        onRestored({
341	          rows_restored: res.data.rows_restored,
342	          safety_snapshot_id: res.data.safety_snapshot_id,
343	        });
344	      } else {
345	        showToast({
346	          title: "Restore failed",
347	          description: res.error.message,
348	          variant: "error",
349	        });
350	        setIsRestoring(false);
351	      }
352	    } catch {
353	      showToast({
354	        title: "Restore failed",
355	        description: "Network error",
356	        variant: "error",
357	      });
358	      setIsRestoring(false);
359	    }
360	  };
361	
362	  const MODAL_OVERLAY: React.CSSProperties = {
363	    position: "fixed",
364	    inset: 0,
365	    background: "var(--io-modal-backdrop)",
366	    display: "flex",
367	    alignItems: "center",
368	    justifyContent: "center",
369	    zIndex: 9999,
370	  };
371	
372	  const MODAL_BOX: React.CSSProperties = {
373	    background: "var(--io-surface-primary)",
374	    border: "1px solid var(--io-border)",
375	    borderRadius: "10px",
376	    padding: "var(--io-space-6)",
377	    maxWidth: 860,
378	    width: "95%",
379	    maxHeight: "85vh",
380	    display: "flex",
381	    flexDirection: "column",
382	    gap: "var(--io-space-4)",
383	  };
384	
385	  return (
386	    <div style={MODAL_OVERLAY}>
387	      <div style={MODAL_BOX}>
388	        {/* Header */}
389	        <div
390	          style={{
391	            display: "flex",
392	            justifyContent: "space-between",
393	            alignItems: "flex-start",
394	          }}
395	        >
396	          <div>
397	            <h2
398	              style={{
399	                margin: 0,
400	                fontSize: "16px",
401	                fontWeight: 700,
402	                color: "var(--io-text-primary)",
403	              }}
404	            >
405	              Restore Snapshot
406	            </h2>
407	            {snapshotLabel && (
408	              <p
409	                style={{
410	                  margin: "2px 0 0",
411	                  fontSize: "12px",
412	                  color: "var(--io-text-muted)",
413	                }}
414	              >
415	                {snapshotLabel}
416	              </p>
417	            )}
418	          </div>
419	          <button
420	            style={{ ...BTN_SECONDARY, padding: "4px 10px", fontSize: "12px" }}
421	            onClick={onClose}
422	          >
423	            Cancel
424	          </button>
425	        </div>
426	
427	        {/* Step 1: Loading */}
428	        {step === 1 && (
429	          <div
430	            style={{
431	              padding: "var(--io-space-6)",
432	              textAlign: "center",
433	              color: "var(--io-text-muted)",
434	            }}
435	          >
436	            {loadError ? (
