451	              style={{
452	                display: "flex",
453	                gap: "var(--io-space-4)",
454	                flexWrap: "wrap",
455	                fontSize: "13px",
456	              }}
457	            >
458	              <span>
459	                <strong style={{ color: "var(--io-text-primary)" }}>
460	                  {preview.total_rows}
461	                </strong>
462	                <span style={{ color: "var(--io-text-muted)", marginLeft: 4 }}>
463	                  rows in snapshot
464	                </span>
465	              </span>
466	              {preview.conflicted_count > 0 && (
467	                <span style={{ color: "var(--io-warning)", fontWeight: 600 }}>
468	                  &#9888; {preview.conflicted_count} conflicted (modified after
469	                  snapshot)
470	                </span>
471	              )}
472	              <span
473	                style={{
474	                  color: "var(--io-text-muted)",
475	                  fontFamily: "monospace",
476	                  fontSize: "11px",
477	                }}
478	              >
479	                Snapshot taken:{" "}
480	                {new Date(preview.snapshot_created_at).toLocaleString()}
481	              </span>
482	            </div>
483	
484	            {/* Mode selector */}
485	            <div
486	              style={{
487	                display: "flex",
488	                gap: "var(--io-space-4)",
489	                alignItems: "center",
490	                flexWrap: "wrap",
491	              }}
492	            >
493	              <label
494	                style={{
495	                  display: "flex",
496	                  gap: 6,
497	                  alignItems: "center",
498	                  cursor: "pointer",
499	                  fontSize: "13px",
500	                }}
501	              >
502	                <input
503	                  type="radio"
504	                  name="restore-mode"
505	                  value="all"
506	                  checked={mode === "all"}
507	                  onChange={() => setMode("all")}
508	                />
509	                Restore all {preview.total_rows} rows
510	              </label>
511	              <label
512	                style={{
513	                  display: "flex",
514	                  gap: 6,
515	                  alignItems: "center",
516	                  cursor: "pointer",
517	                  fontSize: "13px",
518	                }}
519	              >
520	                <input
