3461	// WorkspaceNameModal — used for both create and rename flows
3462	// ---------------------------------------------------------------------------
3463	
3464	function WorkspaceNameModal({
3465	  mode,
3466	  initialName,
3467	  initialDescription = "",
3468	  onConfirm,
3469	  onCancel,
3470	}: {
3471	  mode: "create" | "rename";
3472	  initialName: string;
3473	  initialDescription?: string;
3474	  onConfirm: (name: string, description: string) => void;
3475	  onCancel: () => void;
3476	}) {
3477	  const [name, setName] = useState(initialName);
3478	  const [description, setDescription] = useState(initialDescription);
3479	
3480	  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
3481	    if (e.key === "Enter" && name.trim())
3482	      onConfirm(name.trim(), description.trim());
3483	    if (e.key === "Escape") onCancel();
3484	  }
