// ---------------------------------------------------------------------------
// WorkspaceNameModal — used for both create and rename flows
// ---------------------------------------------------------------------------

function WorkspaceNameModal({
  mode,
  initialName,
  initialDescription = "",
  onConfirm,
  onCancel,
}: {
  mode: "create" | "rename";
  initialName: string;
  initialDescription?: string;
  onConfirm: (name: string, description: string) => void;
  onCancel: () => void;
}) {
  const [name, setName] = useState(initialName);
  const [description, setDescription] = useState(initialDescription);

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter" && name.trim())
      onConfirm(name.trim(), description.trim());
    if (e.key === "Escape") onCancel();
  }

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 9999,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onCancel();
      }}
    >
      <div
        style={{
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: 8,
          padding: "20px 24px",
          minWidth: 360,
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        <div style={{ fontSize: 14, fontWeight: 600, color: "var(--io-text)" }}>
          {mode === "create" ? "New Workspace" : "Rename Workspace"}
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <label
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              fontWeight: 500,
            }}
          >
            Name
          </label>
          <input
            autoFocus
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Workspace name"
            style={{
              padding: "6px 10px",
              background: "var(--io-surface-elevated)",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text)",
              fontSize: 13,
              outline: "none",
            }}
          />
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <label
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              fontWeight: 500,
            }}
          >
            Description <span style={{ fontWeight: 400 }}>(optional)</span>
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Escape") onCancel();
            }}
            placeholder="Brief description of this workspace"
            rows={3}
            style={{
              padding: "6px 10px",
              background: "var(--io-surface-elevated)",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text)",
              fontSize: 13,
              outline: "none",
              resize: "vertical",
              fontFamily: "inherit",
            }}
          />
        </div>
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
          <button
            onClick={onCancel}
            style={{
              padding: "5px 14px",
              background: "transparent",
              border: "1px solid var(--io-border)",
              borderRadius: 4,
              color: "var(--io-text-muted)",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Cancel
          </button>
          <button
            onClick={() => {
              if (name.trim()) onConfirm(name.trim(), description.trim());
            }}
            disabled={!name.trim()}
            style={{
              padding: "5px 14px",
              background: "var(--io-accent)",
              border: "none",
              borderRadius: 4,
              color: "#fff",
              fontSize: 12,
              cursor: name.trim() ? "pointer" : "not-allowed",
              opacity: name.trim() ? 1 : 0.5,
            }}
          >
            {mode === "create" ? "Create" : "Rename"}
          </button>
        </div>
      </div>
    </div>
  );
}

