return (
  <div style={MODAL_OVERLAY}>
    <div style={MODAL_BOX}>
      {/* Header */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
        }}
      >
        <div>
          <h2
            style={{
              margin: 0,
              fontSize: "16px",
              fontWeight: 700,
              color: "var(--io-text-primary)",
            }}
          >
            Restore Snapshot
          </h2>
          {snapshotLabel && (
            <p
              style={{
                margin: "2px 0 0",
                fontSize: "12px",
                color: "var(--io-text-muted)",
              }}
            >
              {snapshotLabel}
            </p>
          )}
        </div>
        <button
          style={{ ...BTN_SECONDARY, padding: "4px 10px", fontSize: "12px" }}
          onClick={onClose}
        >
          Cancel
        </button>
      </div>

      {/* Step 1: Loading */}
      {step === 1 && (
        <div
          style={{
            padding: "var(--io-space-6)",
            textAlign: "center",
            color: "var(--io-text-muted)",
          }}

                  >
                    Clear
                  </button>
                </div>
              )}
            </div>

            {/* Diff table */}
            <div
              style={{
                flex: 1,
                overflowY: "auto",
                overflowX: "auto",
                border: "1px solid var(--io-border)",
                borderRadius: 6,
              }}
            >
              <RestorePreviewDiffTable
                rows={preview.rows}
                mode={mode}
                selectedIds={selectedRowIds}
                onToggle={toggleRow}
              />
            </div>

            {/* Safety snapshot checkbox */}
            <label
              style={{
                display: "flex",
                gap: 8,
                alignItems: "center",
                cursor: "pointer",
                fontSize: "13px",
                color: "var(--io-text-primary)",
              }}
            >
              <input
                type="checkbox"
                checked={createSafetySnapshot}
                onChange={(e) => setCreateSafetySnapshot(e.target.checked)}
              />
              Create a safety snapshot of the current state before restoring
            </label>

            {/* Footer */}
            <div
              style={{
                display: "flex",
                gap: "var(--io-space-3)",
                justifyContent: "flex-end",
              }}
            >
              <button style={BTN_SECONDARY} onClick={onClose}>
                Cancel
              </button>
              <button
                style={BTN_PRIMARY}
                onClick={() => setStep(3)}
                disabled={mode === "selective" && selectedRowIds.size === 0}
              >
                Continue ({rowCount} row{rowCount !== 1 ? "s" : ""})
              </button>
            </div>
          </>
        )}

        {/* Step 3: Final Confirmation */}
        {step === 3 && preview && (
          <>
            <div
              style={{
                padding: "var(--io-space-4)",
                background: "var(--io-warning-subtle)",
                borderRadius: 6,
                border: "1px solid var(--io-warning)",
                fontSize: "13px",
                color: "var(--io-text-primary)",
                lineHeight: 1.6,
              }}
            >
              <strong>
                You are about to restore {rowCount} row
                {rowCount !== 1 ? "s" : ""}
              </strong>{" "}
              from snapshot
              {snapshotLabel
                ? ` "${snapshotLabel}"`
                : ` ${snapshotId.slice(0, 8)}…`}
              {createSafetySnapshot && (
                <span>
                  {" "}
                  A safety snapshot of the current state will be created first.
                </span>
              )}
              {preview.conflicted_count > 0 && mode === "all" && (
                <div
                  style={{
                    marginTop: 6,
                    color: "var(--io-warning)",
                    fontWeight: 600,
                  }}
                >
                  &#9888; {preview.conflicted_count} conflicted row
                  {preview.conflicted_count !== 1 ? "s" : ""} will be
                  overwritten.
                </div>
              )}
            </div>

            <div
              style={{
                display: "flex",
                gap: "var(--io-space-3)",
                justifyContent: "flex-end",
              }}
            >
              <button style={BTN_SECONDARY} onClick={() => setStep(2)}>
                Back
              </button>
              <button
                style={{ ...BTN_PRIMARY, background: "var(--io-danger)" }}
                onClick={handleRestore}
                disabled={isRestoring}
              >
                {isRestoring
                  ? "Restoring…"
                  : `Restore ${rowCount} Row${rowCount !== 1 ? "s" : ""}`}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

